# 190_AB_ROS_BRIDGE_TRUE_WITH_189_GROUP_GATE
# - Based on 184.
# - Fix 1: A/B worker namespaces get _AB_MASTER_RESET_MODE_181=True, so workers yield before wrapper's single shared_world.reset().
# - Fix 2: A/B loop no longer reads obs["m0609_robot"]; it reads robot.get_joint_positions(), so B uses m0609_robot_B correctly.
# - Keeps 184 behavior: B VGC10 is explicitly ensured, A/B standby home pose is forced, A forklift after 2 boxes, B stack only.
# - 186: top-level ROS2 Bridge ON + embedded ENABLE_ROS2_BRIDGE=True.
# - 190: only adds 189 gate movement logic for /World/Group and /World/Group_01.

from isaacsim import SimulationApp
simulation_app = SimulationApp({"headless": False})

# 186_FIX: /World/Graph/ROS_Camera의 ROS2CameraHelper가 publisher를 만들도록
# wrapper 레벨에서도 ROS2 Bridge extension을 강제로 활성화한다.
try:
    from isaacsim.core.utils.extensions import enable_extension
    enable_extension("isaacsim.ros2.bridge")
    simulation_app.update()
    print("[186_ROS2_BRIDGE] isaacsim.ros2.bridge enabled at wrapper level")
except Exception as _ros_bridge_exc:
    print(f"[186_ROS2_BRIDGE][WARN] failed to enable ROS2 bridge: {_ros_bridge_exc}")

