_gate_last_poll_time = [None]


def set_gate_z(stage, path, z):
    prim = stage.GetPrimAtPath(path)
    if not prim.IsValid():
        print("[190_GATE][ERROR] Not found: " + path)
        return False
    x, y = GATE_FIXED_XY.get(path, (0.0, 0.0))
    UsdGeom.XformCommonAPI(prim).SetTranslate(Gf.Vec3d(float(x), float(y), float(z)))
    print("[190_GATE] " + path + " -> (" + str(x) + ", " + str(y) + ", " + str(z) + ")")
    return True


def trigger_gate(zone: str):
    """
    Zone A: 4초 후 Group 닫힘 → 5초 후 열림
    Zone B: 6초 후 Group_01 닫힘 → 8초 후 열림
    remaining_sec 기준 → pause 중 poll_gate가 호출되지 않으면 시간 흐름 없음
    """
    zone = str(zone).strip().upper()
    if zone not in GATE_GROUPS:
        print("[190_GATE] Unknown zone: " + zone)
        return
    group_path = GATE_GROUPS[zone][0]

    # 이미 같은 gate가 pending 중이면 중복 등록 방지
    for _, gp, _ in _gate_pending:
        if gp == group_path:
            print("[190_GATE] SKIP — already pending: " + group_path)
            return

    delay = ZONE_DELAY.get(zone, 0)
    duration = GATE_DOWN_DURATION.get(zone, 2)
    _gate_pending.append((float(delay), group_path, "down"))
    _gate_pending.append((float(delay + duration), group_path, "up"))
    _gate_last_poll_time[0] = None
    print("[190_GATE] Zone " + zone + " -> " + group_path +
          " DOWN in " + str(delay) + "s, UP in " + str(delay + duration) + "s")


def poll_gate(stage):
    """is_playing 중에만 호출되도록 main loop에서 제한한다."""
    if not _gate_pending:
        _gate_last_poll_time[0] = None
        return
    now = _time_module.time()
    if _gate_last_poll_time[0] is None:
        _gate_last_poll_time[0] = now
        return
    dt = now - _gate_last_poll_time[0]
    _gate_last_poll_time[0] = now

    still_pending = []
    for remaining, group_path, action in _gate_pending:
        remaining -= dt
        if remaining <= 0:
            if action == "down":
                set_gate_z(stage, group_path, GATE_Z_DOWN)
                print("[190_GATE] DOWN: " + group_path)
            else:
                set_gate_z(stage, group_path, GATE_Z_UP)
                print("[190_GATE] UP: " + group_path)
        else:
            still_pending.append((remaining, group_path, action))
    _gate_pending.clear()
    _gate_pending.extend(still_pending)


def poll_zone_file(stage):
    """zone_bridge_node가 /tmp/zone_command.txt에 기록한 Zone을 읽어 게이트 트리거."""
    if not os.path.exists(ZONE_FILE):
        return
    try:
        with open(ZONE_FILE, "r") as f:
            zone = f.read().strip().upper()
        if not zone:
            return
        # 읽은 즉시 삭제 → 중복 트리거 원천 차단
        try:
            os.remove(ZONE_FILE)
        except Exception:
            pass
        if zone != _last_zone[0]:
            _last_zone[0] = zone
            trigger_gate(zone)
            print("[190_ZONE] Received: " + zone)
        else:
            print("[190_ZONE] SKIP duplicate: " + zone)
    except Exception as e:
        print("[190_GATE][POLL_ERROR] " + str(e))


def reset_all_gates(stage):
    """초기화 시 모든 게이트를 UP(개방) 상태로 리셋."""
    for zone_paths in GATE_GROUPS.values():
        for path in zone_paths:
            set_gate_z(stage, path, GATE_Z_UP)
    _gate_pending.clear()
    _gate_last_poll_time[0] = None
    _last_zone[0] = None
    print("[190_GATE] 초기화 완료 - 모든 게이트 개방 (Z=" + str(GATE_Z_UP) + ")")


def _load_cell_namespace(label, source):
    ns = {
        "__name__": f"__merged_cell_{label}__",
        "__file__": __file__,
        "__package__": None,
        "simulation_app": simulation_app,
        "_AB_MASTER_RESET_MODE_181": True,
    }
    try:
        exec(compile(source, f"<merged_cell_{label}>", "exec"), ns)
    except Exception as exc:
        print(f"[185_AB][{label}][LOAD_ERROR] {type(exc).__name__}: {exc}")
        traceback.print_exc()
        raise
    return ns


def _safe_next(label, worker, phase="step"):
    try:
        next(worker)
        return True
    except StopIteration:
        print(f"[185_AB][{label}][STOP] worker stopped unexpectedly during {phase}")
        return False
    except Exception as exc:
        print(f"[185_AB][{label}][STEP_ERROR][{phase}] {type(exc).__name__}: {exc}")
        traceback.print_exc()
        return False


def _check_required_paths(stage):
    required = [
        "/World/m0609_A", "/World/m0609_B",
        "/World/APalt", "/World/BPalt",
        "/World/APalt_slot_01", "/World/APalt_slot_02",
        "/World/BPalt_slot_01", "/World/BPalt_slot_02",
        "/World/OriBoxA_01", "/World/OriBoxA_02",
        "/World/OriBoxB_01", "/World/OriBoxB_02",
    ]
    for path in required:
        try:
            prim = stage.GetPrimAtPath(path)
            if not prim or not prim.IsValid():
                print(f"[185_AB][PATH_WARN] missing or invalid: {path}")
        except Exception as exc:
            print(f"[185_AB][PATH_WARN] check failed: {path}: {exc}")


def _get_scene_robot(shared_world, robot_name):
    try:
        return shared_world.scene.get_object(robot_name)
    except Exception as exc:
        print(f"[185_STANDBY][WARN] scene.get_object failed: {robot_name}: {type(exc).__name__}: {exc}")
        return None


def _force_robot_home_pose(label, robot):
    if robot is None:
        print(f"[185_STANDBY][{label}][WARN] robot object is None")
        return False
    try:
        import numpy as _np
        try:
            robot.initialize()
        except Exception:
            pass
        n = int(getattr(robot, "num_dof", 6))
        q = _np.zeros(n, dtype=float)
        robot.set_joint_positions(q)
        try:
            robot.set_joint_velocities(_np.zeros(n, dtype=float))
        except Exception:
            pass
        print(f"[185_STANDBY][{label}] home/initial zero pose forced. dof={n}")
        return True
    except Exception as exc:
        print(f"[185_STANDBY][{label}][WARN] home pose force failed: {type(exc).__name__}: {exc}")
        traceback.print_exc()
        return False


def _ensure_side_vgc10(label, ns, stage, robot):
    try:
        attach_fn = ns.get("attach_vgc10_to_link6")
        update_fn = ns.get("update_vgc10_suction_anchor")
        root_path = str(ns.get("VGC10_PRIM_PATH", ""))
        suction_path = str(ns.get("VGC10_SUCTION_POINT_PATH", ""))

        if callable(attach_fn):
            attach_fn(stage)
        if callable(update_fn) and robot is not None:
            for _ in range(5):
                update_fn(robot)

        root_ok = bool(root_path and stage.GetPrimAtPath(root_path).IsValid())
        suction_ok = bool(suction_path and stage.GetPrimAtPath(suction_path).IsValid())
        print(
            f"[185_VGC10][{label}] ensured root={root_path} ok={root_ok}, "
            f"suction={suction_path} ok={suction_ok}"
        )
        if not root_ok or not suction_ok:
            print(f"[185_VGC10][{label}][WARN] VGC10/suction point missing after ensure. Check asset path/tool0 path.")
        return root_ok and suction_ok
    except Exception as exc:
        print(f"[185_VGC10][{label}][ERROR] ensure failed: {type(exc).__name__}: {exc}")
        traceback.print_exc()
        return False


class _BoxPhysicsSequencer185:
    def __init__(self, stage, api_ns):
        self.stage = stage
        self.UsdPhysics = api_ns["UsdPhysics"]
        self.Gf = api_ns["Gf"]
        self.sequence = (
            (1.0, "/World/OriBoxA_01"),
            (7.0, "/World/OriBoxB_01"),
            (13.0, "/World/OriBoxA_02"),
            (19.0, "/World/OriBoxB_02"),
        )
        self.start_wall_time = None
        self.next_index = 0
        self.initialized = False
        self.enabled_paths = set()

    def _subtree(self, root_prim):
        stack = [root_prim]
        while stack:
            prim = stack.pop()
            yield prim
            try:
                stack.extend(list(prim.GetChildren()))
            except Exception:
                pass

    def _set_zero_velocity(self, prim):
        try:
            zero = self.Gf.Vec3f(0.0, 0.0, 0.0)
        except Exception:
            zero = (0.0, 0.0, 0.0)
        for attr_name in ("physics:velocity", "physics:angularVelocity"):
            try:
                attr = prim.GetAttribute(attr_name)
                if attr:
                    attr.Set(zero)
            except Exception:
                pass

    def _set_collision_enabled_subtree(self, root_prim, enabled):
        changed = 0
        for prim in self._subtree(root_prim):
            try:
                try:
                    has_collision_api = bool(prim.HasAPI(self.UsdPhysics.CollisionAPI))
                except Exception:
                    has_collision_api = bool(prim.GetAttribute("physics:collisionEnabled"))
                if not has_collision_api:
                    continue
                collision_api = self.UsdPhysics.CollisionAPI(prim)
                attr = collision_api.GetCollisionEnabledAttr()
                if not attr:
                    attr = collision_api.CreateCollisionEnabledAttr(bool(enabled))
                attr.Set(bool(enabled))
                changed += 1
            except Exception as exc:
                print(f"[185_BOX_SEQ][WARN] collision set failed: {prim.GetPath()} enabled={enabled}: {exc}")
        return changed

    def _set_box_physics(self, root_path, enabled, reason):
        prim = self.stage.GetPrimAtPath(root_path)
        if not prim or not prim.IsValid():
            print(f"[185_BOX_SEQ][WARN] missing box prim: {root_path}")
            return False
        try:
            rb_api = self.UsdPhysics.RigidBodyAPI.Apply(prim)
            rb_attr = rb_api.GetRigidBodyEnabledAttr()
            if not rb_attr:
                rb_attr = rb_api.CreateRigidBodyEnabledAttr(bool(enabled))
            rb_attr.Set(bool(enabled))

            kin_attr = prim.GetAttribute("physics:kinematicEnabled")
            if kin_attr:
                kin_attr.Set(False)

            if not enabled:
                self._set_zero_velocity(prim)

            collision_count = self._set_collision_enabled_subtree(prim, enabled)

            if enabled:
                self.enabled_paths.add(root_path)
                state = "ON"
            else:
                self.enabled_paths.discard(root_path)
                state = "OFF"

            print(
                f"[185_BOX_SEQ] {state} {root_path} reason={reason}, "
                f"rigidBodyEnabled={enabled}, collision_subtree_count={collision_count}"
            )
            return True
        except Exception as exc:
            print(f"[185_BOX_SEQ][ERROR] physics set failed: {root_path} enabled={enabled}: {type(exc).__name__}: {exc}")
            traceback.print_exc()
            return False

    def force_all_off(self, reason="force_all_off"):
        unique_paths = []
        for _delay, path in self.sequence:
            if path not in unique_paths:
                unique_paths.append(path)
        print(f"[185_BOX_SEQ] force all pre-placed boxes OFF reason={reason}")
        for path in unique_paths:
            self._set_box_physics(path, False, reason)

    def initialize(self):
        self.force_all_off("sequence_initialize_all_off")
        self.start_wall_time = time.time()
        self.next_index = 0
        self.initialized = True
        print("[185_BOX_SEQ] release order after strict OFF: A01@1.0s -> B01@7.0s -> A02@13.0s -> B02@19.0s")

    def update(self):
        if not self.initialized:
            return
        elapsed = time.time() - float(self.start_wall_time)
        while self.next_index < len(self.sequence):
            delay_sec, root_path = self.sequence[self.next_index]
            if elapsed < float(delay_sec):
                break
            self._set_box_physics(root_path, True, f"scheduled_release_t={elapsed:.2f}s")
            self.next_index += 1


def main():
    print("[185_AB] loading isolated A/B namespaces")
    A = _load_cell_namespace("A", _CELL_A_SOURCE)
    B = _load_cell_namespace("B", _CELL_B_SOURCE)

    World = A["World"]
    shared_world = World(stage_units_in_meters=1.0)

    print("[185_AB] creating A/B workers in shared-reset mode")
    worker_a = A["make_worker_A"](shared_world)
    worker_b = B["make_worker_B"](shared_world)
    workers = [["A", worker_a, True], ["B", worker_b, True]]

    # Phase 1: with _AB_MASTER_RESET_MODE_181=True, this only adds tasks and yields.
    for row in workers:
        label, worker, _alive = row
        print(f"[185_AB][{label}] phase1 add_task")
        row[2] = _safe_next(label, worker, phase="add_task")

    box_sequence_185 = None
    try:
        stage = A["omni"].usd.get_context().get_stage()
        box_sequence_185 = _BoxPhysicsSequencer185(stage, A)
        box_sequence_185.force_all_off("pre_shared_reset_usd_authored_physics_off")
    except Exception as exc:
        print(f"[185_AB][BOX_SEQ_PRE_RESET_OFF_WARN] {type(exc).__name__}: {exc}")
        traceback.print_exc()

    print("[185_AB] one shared_world.reset() after both A/B tasks were added")
    try:
        shared_world.reset()
    except Exception as exc:
        print(f"[185_AB][SHARED_RESET_ERROR] {type(exc).__name__}: {exc}")
        traceback.print_exc()
        simulation_app.close()
        return

    # 190_GATE: 189의 gate 초기 상태와 동일하게 /World/Group, /World/Group_01을 UP으로 리셋.
    try:
        stage = A["omni"].usd.get_context().get_stage()
        reset_all_gates(stage)
    except Exception as exc:
        print(f"[190_GATE][RESET_WARN] {type(exc).__name__}: {exc}")
        traceback.print_exc()

    if box_sequence_185 is not None:
        try:
            box_sequence_185.force_all_off("post_shared_reset_usd_authored_physics_off")
        except Exception as exc:
            print(f"[185_AB][BOX_SEQ_POST_RESET_OFF_WARN] {type(exc).__name__}: {exc}")
            traceback.print_exc()

    # Phase 2: each worker initializes its own robot/controllers after the single shared reset.
    for row in workers:
        label, worker, alive = row
        if not alive:
            continue
        print(f"[185_AB][{label}] phase2 init after shared reset")
        row[2] = _safe_next(label, worker, phase="post_reset_init")

    # Explicit gripper + home standby guarantee.
    try:
        stage = A["omni"].usd.get_context().get_stage()
        robot_a = _get_scene_robot(shared_world, "m0609_robot_A")
        robot_b = _get_scene_robot(shared_world, "m0609_robot_B")

        _force_robot_home_pose("A", robot_a)
        _force_robot_home_pose("B", robot_b)

        _ensure_side_vgc10("A", A, stage, robot_a)
        _ensure_side_vgc10("B", B, stage, robot_b)

        for _ in range(10):
            try:
                if callable(A.get("update_vgc10_suction_anchor")) and robot_a is not None:
                    A["update_vgc10_suction_anchor"](robot_a)
                if callable(B.get("update_vgc10_suction_anchor")) and robot_b is not None:
                    B["update_vgc10_suction_anchor"](robot_b)
                shared_world.step(render=True)
            except Exception:
                break
        print("[185_STANDBY] A/B robots are in initial pose; A/B VGC10 grippers ensured before box release sequence.")
    except Exception as exc:
        print(f"[185_STANDBY][WARN] initial standby/gripper ensure failed: {type(exc).__name__}: {exc}")
        traceback.print_exc()

    try:
        stage = A["omni"].usd.get_context().get_stage()
        _check_required_paths(stage)
        if box_sequence_185 is None:
            box_sequence_185 = _BoxPhysicsSequencer185(stage, A)
        box_sequence_185.force_all_off("post_worker_init_strict_all_off")
        box_sequence_185.initialize()
    except Exception as exc:
        print(f"[185_AB][BOX_SEQ_INIT_WARN] {type(exc).__name__}: {exc}")
        traceback.print_exc()

    print("[185_AB] parallel loop start: strict box sequence update -> shared_world.step -> A.step/B.step")
    while simulation_app.is_running():
        if box_sequence_185 is not None:
            try:
                box_sequence_185.update()
            except Exception as exc:
                print(f"[185_AB][BOX_SEQ_STEP_WARN] {type(exc).__name__}: {exc}")
                traceback.print_exc()

        try:
            shared_world.step(render=True)
        except Exception as exc:
            print(f"[185_AB][WORLD_STEP_ERROR] {type(exc).__name__}: {exc}")
            traceback.print_exc()
            break

        # 190_GATE: 189처럼 Play 중에만 zone file을 읽고 /World/Group, /World/Group_01 Z 이동 처리.
        try:
            if shared_world.is_playing():
                stage_now = A["omni"].usd.get_context().get_stage()
                poll_zone_file(stage_now)
                poll_gate(stage_now)
            else:
                _gate_last_poll_time[0] = None
        except Exception as exc:
            print(f"[190_GATE][STEP_WARN] {type(exc).__name__}: {exc}")
            traceback.print_exc()

        for row in workers:
            label, worker, alive = row
            if not alive:
                continue
            row[2] = _safe_next(label, worker, phase="loop")

        time.sleep(0.01)

    print("[185_AB] closing shared SimulationApp")
    simulation_app.close()


if __name__ == "__main__":
    main()
